 <script>
 document.addEventListener('DOMContentLoaded', function() {
 const navLinks = document.querySelectorAll('.nav-link-custom');
 const menuToggle = document.getElementById('portalMenuToggle');
 const sidebar = document.querySelector('.portal-sidebar');
 const overlay = document.getElementById('portalOverlay');
 
 navLinks.forEach(link => {
 link.addEventListener('mouseenter', function() {
 if (!this.classList.contains('active')) {
 this.style.transform = 'translateX(8px)';
 }
 });
 
 link.addEventListener('mouseleave', function() {
 if (!this.classList.contains('active')) {
 this.style.transform = 'translateX(0)';
 }
 });
 
 link.addEventListener('click', function() {
 if (sidebar && sidebar.classList.contains('show')) {
 sidebar.classList.remove('show');
 overlay.classList.remove('show');
 }
 });
 });
 
 if (menuToggle) {
 menuToggle.addEventListener('click', function() {
 sidebar.classList.toggle('show');
 overlay.classList.toggle('show');
 });
 }
 
 if (overlay) {
 overlay.addEventListener('click', function() {
 sidebar.classList.remove('show');
 overlay.classList.remove('show');
 });
 const sidebarClose = document.getElementById('portalSidebarClose');
 if (sidebarClose) {
 sidebarClose.addEventListener('click', function() {
 sidebar.classList.remove('show');
 overlay.classList.remove('show');
 });
 }
 }
 
 const portalNotificationToggle = document.getElementById('portalNotificationToggle');
 const portalNotificationDropdown = document.getElementById('portalNotificationDropdown');
 const portalMessageToggle = document.getElementById('portalMessageToggle');
 const portalMessageDropdown = document.getElementById('portalMessageDropdown');
 
 if (portalNotificationToggle && portalNotificationDropdown) {
 portalNotificationToggle.addEventListener('click', function(event) {
 event.stopPropagation();
 portalNotificationDropdown.classList.toggle('show');
 if (portalMessageDropdown) portalMessageDropdown.classList.remove('show');
 });
 
 document.addEventListener('click', function(event) {
 if (!portalNotificationDropdown.contains(event.target) && !portalNotificationToggle.contains(event.target)) {
 portalNotificationDropdown.classList.remove('show');
 }
 });
 }
 
 if (portalMessageToggle && portalMessageDropdown) {
 portalMessageToggle.addEventListener('click', function(event) {
 event.stopPropagation();
 portalMessageDropdown.classList.toggle('show');
 if (portalNotificationDropdown) portalNotificationDropdown.classList.remove('show');
 });
 
 document.addEventListener('click', function(event) {
 if (!portalMessageDropdown.contains(event.target) && !portalMessageToggle.contains(event.target)) {
 portalMessageDropdown.classList.remove('show');
 }
 });
 }
 });
 </script>
